+                    && method.getParameters().get(0).getType().toString().contains("CommandCause")
+                    && method.getParameters().get(1).getType().toString().contains("CommandContext")) {
+                method.setType("CommandResult");
+                method.setParameters(NodeList.nodeList(method.getParameter(1).clone()));
