+            } else if (type.endsWith("GameInitializationEvent")) {
+                method.getParameter(0).setType("LoadedGameEvent");
+                changed = true;
+            } else if (type.endsWith("GameStoppingServerEvent")) {
+                method.getParameter(0).setType("StoppedGameEvent");
