+    private static String joinArgs(NodeList<Expression> expressions) {
+        StringBuilder builder = new StringBuilder();
+        for (int i = 0; i < expressions.size(); i++) {
+            if (i > 0) {
+                builder.append(", ");
+            }
+            builder.append(expressions.get(i));
+        }
+        return builder.toString();
+    }
